from typing import List

class Solution:
    def FindNextKeywords(self, commands: List[str], prefix: str) -> List[str]:
        # 用集合去重，最后排序输出
        seen = set()
        for raw in commands:
            # 忽略命令首尾无意义空格
            s = raw.strip()
            # 以前缀开头才处理
            if not s.startswith(prefix):
                continue
            # 前缀之后的部分，再去掉首尾空格
            rest = s[len(prefix):].strip()
            if not rest:
                continue
            # 第一个关键字：到下一个空格为止
            sp = rest.find(" ")
            word = rest if sp == -1 else rest[:sp]
            if word:
                seen.add(word)
        # 按字典序排序输出
        return sorted(seen)
```

