import java.util.*;

public class Solution {
    public String[] FindNextKeywords(String[] commands, String prefix) {
        // TreeSet 同时完成去重与字典序排序
        TreeSet<String> seen = new TreeSet<>();
        for (String raw : commands) {
            String s = raw.trim(); // 去除首尾空格
            if (!s.startsWith(prefix)) {
                continue; // 不符合前缀跳过
            }
            String rest = s.substring(prefix.length()).trim(); // 去除前缀和首尾空格
            if (rest.isEmpty()) {
                continue;
            }
            int sp = rest.indexOf(' '); // 查找第一个空格
            String word = sp < 0 ? rest : rest.substring(0, sp); // 提取关键字
            if (!word.isEmpty()) {
                seen.add(word);
            }
        }
        // 返回有序结果
        return seen.toArray(new String[0]);
    }
}
