```javascript
var FindNextKeywords = function(commands, prefix) {
    const seen = new Set();
    for (const raw of commands) {
        // 忽略命令首尾无意义空格
        const s = raw.trim();
        // 以前缀开头才处理
        if (!s.startsWith(prefix)) continue;
        // 前缀之后的部分，再去掉首尾空格
        const rest = s.substring(prefix.length).trim();
        if (rest.length === 0) continue;
        // 第一个关键字：到下一个空格为止
        const sp = rest.indexOf(' ');
        const word = sp === -1 ? rest : rest.substring(0, sp);
        if (word.length > 0) seen.add(word);
    }
    // 转为数组并按字典序排序
    return Array.from(seen).sort();
};
